    ([Description("Short title for the note")] string title,
     [Description("The note content")] string content) =>
    {
        notes.Add(new ResearchNote(title, content));
        Console.WriteLine($"  📝 Note saved: {title}");
        return $"Note saved: '{title}' ({content.Length} chars)";
    },
    "TakeNote",
    "Save a research note with a title and content to organize findings.");

// --- Build the agent ---

IChatClient chatClient = new OpenAIClient(apiKey)
    .GetChatClient(modelId)
    .AsIChatClient();

var agent = new ChatClientAgent(
    chatClient,
    name: "ResearchAgent",
    description: "Researches topics by searching the web and organizing findings.",
    instructions: """
        You are a research agent. Your job is to thoroughly research a topic using the
        available tools, then deliver a clear summary.

        Follow this process:
        1. Use SearchWeb with 2–3 different queries to explore the topic from multiple angles.
        2. After each search, use TakeNote to record the most important findings.
        3. Once you have gathered enough information, write a comprehensive summary that
           synthesizes your notes into a coherent report with key takeaways.

        Always take notes before writing the final summary.
        """,
    tools: [searchWebTool, takeNoteTool]);

// --- Prompt the user ---

Console.Write("Enter a research topic: ");
var topic = Console.ReadLine()?.Trim();
if (string.IsNullOrEmpty(topic))
{
    Console.WriteLine("No topic provided. Exiting.");
    return;
}

Console.WriteLine($"\n🔍 Researching: {topic}\n");

// --- Run the agent with streaming output ---

var session = await agent.CreateSessionAsync();

var runOptions = new ChatClientAgentRunOptions(new ChatOptions
{
    Temperature = 0f,
    MaxOutputTokens = 2048,
});

await foreach (var update in agent.RunStreamingAsync(
    $"Research the following topic and provide a comprehensive summary: {topic}",
    session,
    runOptions))
{
    if (!string.IsNullOrEmpty(update.Text))
    {
        Console.Write(update.Text);
    }
}

Console.WriteLine();

// --- Display collected research notes ---

if (notes.Count > 0)
{
    Console.WriteLine("\n📋 Research Notes Collected:");
    Console.WriteLine(new string('─', 60));
    foreach (var note in notes)
    {
        Console.WriteLine($"\n  📝 {note.Title}");
        Console.WriteLine($"     {note.Content}");
    }

    Console.WriteLine(new string('─', 60));
}

// --- Types ---

record ResearchNote(string Title, string Content);

